# =====================================================================
# Section 26 — Output Panel Height Clamping (BUG: off-screen drag)
# =====================================================================
print("\n--- Section 26: Output Panel Height Clamping ---")

# 26a: _clamp_output_height reduces height when it exceeds effective max
window.resize(600, 400)
app.processEvents()
_s26a_max = window.output_handle._effective_max_height()
window.output.setFixedHeight(window.height() * 3)  # exceeds effective max
app.processEvents()
window._clamp_output_height()
app.processEvents()
check(window.output.height() <= _s26a_max, f"26a: output clamped to effective max ({window.output.height()} <= {_s26a_max})")

# 26b: height stays at or above OUTPUT_MIN_HEIGHT
window.resize(600, 100)  # half = 50, but min is 80
app.processEvents()
window.output.setFixedHeight(300)
window._clamp_output_height()
app.processEvents()
check(window.output.height() >= scaffold.OUTPUT_MIN_HEIGHT,
      f"26b: output height >= OUTPUT_MIN_HEIGHT ({window.output.height()} >= {scaffold.OUTPUT_MIN_HEIGHT})")

# 26c: DragHandle._effective_max_height respects window size and siblings
window.resize(600, 400)
app.processEvents()
eff_max = window.output_handle._effective_max_height()
_s26c_parent = window.output.parentWidget()
check(eff_max <= _s26c_parent.height(), f"26c: effective max <= parent height ({eff_max} <= {_s26c_parent.height()})")
check(eff_max >= scaffold.OUTPUT_MIN_HEIGHT, f"26c: effective max >= OUTPUT_MIN_HEIGHT ({eff_max} >= {scaffold.OUTPUT_MIN_HEIGHT})")

# 26d: MainWindow has resizeEvent and showEvent that handle clamping
check(hasattr(scaffold.MainWindow, "resizeEvent"), "26d: MainWindow has resizeEvent override")
check(hasattr(scaffold.MainWindow, "showEvent"), "26d: MainWindow has showEvent override")

# 26e: QSettings is updated when clamping occurs
window.resize(600, 400)
app.processEvents()
_s26e_max = window.output_handle._effective_max_height()
window.output.setFixedHeight(window.height() * 3)
app.processEvents()
window._clamp_output_height()
app.processEvents()
saved = int(window.settings.value("output/height", 0))
check(saved <= _s26e_max, f"26e: QSettings updated after clamp ({saved} <= {_s26e_max})")

# 26f: height within limits is not altered
window.resize(600, 600)
app.processEvents()
window.output.setFixedHeight(150)
app.processEvents()
window._clamp_output_height()
app.processEvents()
check(window.output.height() == 150, f"26f: height within limits unchanged ({window.output.height()} == 150)")

# Restore window size for cleanup
window.resize(scaffold.DEFAULT_WINDOW_WIDTH, scaffold.DEFAULT_WINDOW_HEIGHT)
app.processEvents()

# 26g–26i use a dedicated window to guarantee the form view is visible and laid out
_s26_win2 = scaffold.MainWindow(tool_path=str(Path(__file__).parent / "tests" / "test_minimal.json"))
_s26_win2.show()
_s26_win2.resize(1200, 800)
app.processEvents()

# 26g (B1.1): _effective_max_height accounts for sibling heights
_s26_parent = _s26_win2.output.parentWidget()
_s26_layout = _s26_parent.layout() if _s26_parent else None
_s26_sibling_total = 0
if _s26_layout is not None:
    for _s26_i in range(_s26_layout.count()):
        _s26_item = _s26_layout.itemAt(_s26_i)
        _s26_w = _s26_item.widget() if _s26_item is not None else None
        if _s26_w is None or _s26_w is _s26_win2.output:
            continue
        if not _s26_w.isVisible():
            continue
        _s26_sh = _s26_w.sizeHint().height()
        if _s26_sh > 0:
            _s26_sibling_total += min(_s26_w.height(), _s26_sh)
        else:
            _s26_sibling_total += _s26_w.height()
_s26_safety = 24
_s26_expected_max = _s26_parent.height() - _s26_sibling_total - _s26_safety
_s26_eff = _s26_win2.output_handle._effective_max_height()
check(_s26_eff <= _s26_expected_max,
      f"26g (B1.1): effective max accounts for siblings ({_s26_eff} <= {_s26_expected_max})")
check(_s26_eff >= scaffold.OUTPUT_MIN_HEIGHT,
      f"26g (B1.1): effective max >= OUTPUT_MIN_HEIGHT ({_s26_eff} >= {scaffold.OUTPUT_MIN_HEIGHT})")

# 26h (B1.2): After max drag, output bottom does not exceed window bottom
_s26_win2.output.setFixedHeight(_s26_win2.output_handle._effective_max_height())
app.processEvents()
QTest.qWaitForWindowExposed(_s26_win2)
app.processEvents()
_s26_out_bottom = _s26_win2.output.mapToGlobal(QPoint(0, _s26_win2.output.height())).y()
_s26_win_bottom = _s26_win2.mapToGlobal(QPoint(0, _s26_win2.height())).y()
_s26_slack = 8
check(_s26_out_bottom <= _s26_win_bottom + _s26_slack,
      f"26h (B1.2): output bottom ({_s26_out_bottom}) <= window bottom ({_s26_win_bottom}) + slack")

# 26i (B1.3): Hidden siblings are not counted
# The _output_search_widget is always hidden. Show it and verify effective max decreases.
_s26_search_w = _s26_win2._output_search_widget
check(not _s26_search_w.isVisible(), "26i (B1.3): search widget starts hidden")
app.processEvents()
_s26_win2.adjustSize()
app.processEvents()
_s26_before = _s26_win2.output_handle._effective_max_height()
_s26_search_w.setVisible(True)
app.processEvents()
_s26_search_w.adjustSize()
app.processEvents()
_s26_after = _s26_win2.output_handle._effective_max_height()
check(_s26_before > 0 and _s26_after > 0,
      f"26i (B1.3): layout completed before measurement (before={_s26_before}, after={_s26_after})")
check(_s26_after < _s26_before,
      f"26i (B1.3): showing hidden sibling decreases effective max ({_s26_after} < {_s26_before})")
_s26_search_w.setVisible(False)
app.processEvents()

_s26_win2.close()
_s26_win2.deleteLater()
app.processEvents()

# 26j–26k use a dedicated window for drag-grow scrollbar coherence tests
from PySide6.QtGui import QMouseEvent
from PySide6.QtCore import QPointF, QEvent

_s26_win3 = scaffold.MainWindow(tool_path=str(Path(__file__).parent / "tests" / "test_minimal.json"))
_s26_win3.show()
_s26_win3.resize(1000, 800)
QTest.qWaitForWindowExposed(_s26_win3)
app.processEvents()

# Fill output with 200 lines
_s26j_cursor = _s26_win3.output.textCursor()
_s26j_cursor.movePosition(_s26j_cursor.MoveOperation.End)
for _s26j_i in range(200):
    _s26j_cursor.insertText(f"line {_s26j_i}\n")
_s26_win3.output.setTextCursor(_s26j_cursor)
app.processEvents()

# 26j: scrollbar range stays coherent after drag-grow (scroll at bottom)
_s26_win3.output.setFixedHeight(scaffold.OUTPUT_MIN_HEIGHT)
app.processEvents()
_s26j_sb = _s26_win3.output.verticalScrollBar()
_s26j_sb.setValue(_s26j_sb.maximum())
app.processEvents()

# Verify starting state: at bottom
check(_s26j_sb.value() >= _s26j_sb.maximum() - 1,
      f"26j: scrollbar starts at bottom ({_s26j_sb.value()} >= {_s26j_sb.maximum() - 1})")

# Simulate drag-grow via DragHandle.mouseMoveEvent
_s26j_eff = _s26_win3.output_handle._effective_max_height()
_s26j_handle = _s26_win3.output_handle
_s26j_handle._dragging = True
_s26j_handle._drag_start_h = scaffold.OUTPUT_MIN_HEIGHT
_s26j_handle._drag_start_y = 500.0
_s26j_target_y = 500.0 - (_s26j_eff - scaffold.OUTPUT_MIN_HEIGHT)
_s26j_event = QMouseEvent(
    QEvent.Type.MouseMove,
    QPointF(0, 0),
    QPointF(0, _s26j_target_y),
    Qt.MouseButton.LeftButton,
    Qt.MouseButton.LeftButton,
    Qt.KeyboardModifier.NoModifier,
)
_s26j_handle.mouseMoveEvent(_s26j_event)
app.processEvents()

# Assert: scrollbar at new maximum (still at bottom)
check(_s26j_sb.value() >= _s26j_sb.maximum() - 1,
      f"26j: scrollbar stays at bottom after drag-grow ({_s26j_sb.value()} >= {_s26j_sb.maximum() - 1})")

# Assert: document's last block visible in viewport
_s26j_first_vis = _s26_win3.output.firstVisibleBlock().blockNumber()
_s26j_vis_lines = max(1, _s26_win3.output.viewport().height() // _s26_win3.output.fontMetrics().lineSpacing())
_s26j_total = _s26_win3.output.document().blockCount()
check(_s26j_first_vis + _s26j_vis_lines >= _s26j_total - 1,
      f"26j: last block visible ({_s26j_first_vis} + {_s26j_vis_lines} >= {_s26j_total - 1})")
_s26j_handle._dragging = False

# 26k: scroll position preserved when not at bottom
_s26_win3.output.setFixedHeight(scaffold.OUTPUT_MIN_HEIGHT)
app.processEvents()
_s26k_sb = _s26_win3.output.verticalScrollBar()
_s26k_sb.setValue(_s26k_sb.maximum() // 2)
app.processEvents()
_s26k_before = _s26k_sb.value()

# Simulate drag-grow from mid-scroll
_s26k_eff = _s26_win3.output_handle._effective_max_height()
_s26j_handle._dragging = True
_s26j_handle._drag_start_h = scaffold.OUTPUT_MIN_HEIGHT
_s26j_handle._drag_start_y = 500.0
_s26k_target_y = 500.0 - (_s26k_eff - scaffold.OUTPUT_MIN_HEIGHT)
_s26k_event = QMouseEvent(
    QEvent.Type.MouseMove,
    QPointF(0, 0),
    QPointF(0, _s26k_target_y),
    Qt.MouseButton.LeftButton,
    Qt.MouseButton.LeftButton,
    Qt.KeyboardModifier.NoModifier,
)
_s26j_handle.mouseMoveEvent(_s26k_event)
app.processEvents()

_s26k_after = _s26k_sb.value()
_s26k_drift = abs(_s26k_after - _s26k_before)
check(_s26k_drift <= 3,
      f"26k: mid-scroll preserved after drag-grow (drift={_s26k_drift}, was={_s26k_before}, now={_s26k_after})")
_s26j_handle._dragging = False

_s26_win3.close()
_s26_win3.deleteLater()
app.processEvents()

# Restore global window size for cleanup
window.resize(scaffold.DEFAULT_WINDOW_WIDTH, scaffold.DEFAULT_WINDOW_HEIGHT)
app.processEvents()


