check(_s66_spin.minimum() == 0, f"66e: delay_spin min is 0 (got {_s66_spin.minimum()})")
check(_s66_spin.maximum() == 3600, f"66e: delay_spin max is 3600 (got {_s66_spin.maximum()})")

# 66f: Delay spinner has "s" suffix
