#           f"{_s169_budget:.1f}s (elapsed={_s169_elapsed:.3f}s)")
print("  (placeholder — no assertions; see TODO for phase-3 fill-in)")


# =====================================================================
# Section 170 — Regex Safety: validation-time heuristic rejects ReDoS-prone patterns
# =====================================================================
# Phase 3B adds a heuristic to _validate_capture_entry that rejects
# patterns with nested quantifiers (H1) or alternation-under-quantifier
# (H2) — the classic ReDoS shapes. Patterns that compile cleanly under
# re.compile can still pin a CPU for minutes on adversarial input; this
# guard stops them at config time rather than letting them reach the
# runtime worker.
#
# Error-message contract: the ValueError text (lowercased) must contain
# at least one of "nested quantifier", "catastrophic", "backtracking",
# or "redos" so the user gets a hint about why the pattern was rejected.
# The seven legitimate patterns below are drawn from real tool schemas
# and must pass both the re.compile check and the new heuristic — they
# guard against over-eager rejection.
print("\n=== SECTION 170: Regex Safety — heuristic rejects ReDoS-prone patterns ===")

import re as _s170_re

_s170_redos_substrings = ("nested quantifier", "catastrophic",
                          "backtracking", "redos")

_s170_bad_patterns = [
    r"^(a+)+$",        # classic nested quantifier
    r"(.*)+",          # nested quantifier
    r"(x+x+)+y",       # nested quantifier
    r"^(a|a)*$",       # alternation under quantifier
]

_s170_good_patterns = [
    r"(\S+)",
    r"open\s+(\d+)/tcp",
    r"^PORT:\s+(.+)$",
    r"Scan completed in (\d+\.\d+)s",
    r"([a-zA-Z0-9_-]+)",
    r"(\d{1,3}(?:\.\d{1,3}){3})",
    r"^\[.*?\]\s+(.+)",
]

for _s170_i, _s170_pat in enumerate(_s170_bad_patterns):
    _s170_entry = {"name": "redos", "source": "stdout",
                   "pattern": _s170_pat, "group": 1}
    _s170_raised = None
    try:
        scaffold._validate_capture_entry(_s170_entry, [])
    except ValueError as _s170_exc:
        _s170_raised = _s170_exc
    check(_s170_raised is not None,
          f"170a.{_s170_i}: _validate_capture_entry raises ValueError "
          f"for ReDoS-prone pattern {_s170_pat!r}")
    if _s170_raised is not None:
        _s170_msg = str(_s170_raised).lower()
        _s170_hit = any(s in _s170_msg for s in _s170_redos_substrings)
        check(_s170_hit,
              f"170b.{_s170_i}: ValueError message for {_s170_pat!r} "
              f"mentions one of "
              f"nested quantifier/catastrophic/backtracking/redos "
              f"(got {_s170_raised!s})")
    else:
        check(False,
              f"170b.{_s170_i}: ValueError message for {_s170_pat!r} "
              f"mentions one of "
              f"nested quantifier/catastrophic/backtracking/redos "
              f"(no exception raised)")

for _s170_i, _s170_pat in enumerate(_s170_good_patterns):
    _s170_compile_ok = True
    try:
        _s170_re.compile(_s170_pat)
    except _s170_re.error:
        _s170_compile_ok = False
    check(_s170_compile_ok,
          f"170c.{_s170_i}: legitimate pattern {_s170_pat!r} "
          f"compiles under re.compile")

    _s170_entry = {"name": "cap", "source": "stdout",
                   "pattern": _s170_pat, "group": 1}
    _s170_validate_raised = None
    try:
        scaffold._validate_capture_entry(_s170_entry, [])
    except ValueError as _s170_exc:
        _s170_validate_raised = _s170_exc
    check(_s170_validate_raised is None,
          f"170d.{_s170_i}: _validate_capture_entry does NOT raise "
          f"for legitimate pattern {_s170_pat!r} "
          f"(got {_s170_validate_raised!s})")


# =====================================================================
# Section 171 — Regex Safety: extract_captures times out on ReDoS patterns
# =====================================================================
# Phase 3B's runtime guard. extract_captures offloads re.search to a
# bounded-execution worker with a 2-second budget. A pattern that would
# otherwise burn CPU for 20+ seconds must return promptly, with a
# "timeout"-flavored entry in the errors list introduced by Section 168.
#
# Section 170's validation-time heuristic would normally reject these
# patterns before they reach the runtime. To exercise the runtime guard
# in isolation, this section BYPASSES validation by feeding a raw dict
# straight to extract_captures — simulating a cascade file built before
# the heuristic existed, or a capture dict constructed programmatically
# rather than through the dialog.
#
# NOTE: until Phase 3B lands, this section will itself hang for ~20s
# while re.search backtracks; that is the failure mode under test.
print("\n=== SECTION 171: Regex Safety — extract_captures times out on ReDoS patterns ===")

_s171_caps = [{"name": "redos", "source": "stdout",
               "pattern": r"^(a+)+$", "group": 0}]
_s171_stream = "a" * 30 + "b"  # calibrated to ~20s without the guard

_s171_t0 = time.monotonic()
_s171_result = scaffold.extract_captures(_s171_caps, _s171_stream, "", 0)
_s171_elapsed = time.monotonic() - _s171_t0
print(f"  (measured extract_captures duration: {_s171_elapsed:.3f}s)")

# 171a: wall-clock budget is 2s (guard) + 1.5s (process spawn overhead
#        on a cold Windows multiprocessing pool).
check(_s171_elapsed < 3.5,
      f"171a: extract_captures on ReDoS pattern returns under 3.5s "
      f"(elapsed={_s171_elapsed:.3f}s)")

if isinstance(_s171_result, tuple) and len(_s171_result) == 2:
    _s171_values, _s171_errors = _s171_result
else:
    _s171_values, _s171_errors = {}, []

_s171_values_dict = _s171_values if isinstance(_s171_values, dict) else {}
# 171b: the timed-out capture must not populate values — preserves the
#        existing "absent = unset" signal that downstream substitution
#        relies on.
check("redos" not in _s171_values_dict,
      f"171b: ReDoS pattern did not populate values['redos'] "
      f"(values={_s171_values_dict!r})")

# 171c: the timeout must surface on the errors list as a distinct entry
#        naming the offending capture, with a message containing
#        "timeout" or "exceeded". Accept tuple/list/dict shapes so the
#        test does not couple to the exact error-entry encoding.
_s171_err_entries = _s171_errors if isinstance(_s171_errors, list) else []
_s171_timeout_match = False
for _s171_e in _s171_err_entries:
    _s171_name = None
    _s171_msg = ""
    if isinstance(_s171_e, (tuple, list)) and len(_s171_e) >= 2:
        _s171_name = _s171_e[0]
        _s171_msg = str(_s171_e[1])
    elif isinstance(_s171_e, dict):
        _s171_name = _s171_e.get("name")
        _s171_msg = str(_s171_e.get("message") or _s171_e.get("error") or "")
    elif isinstance(_s171_e, str):
        _s171_msg = _s171_e
    _s171_msg_l = _s171_msg.lower()
    if _s171_name == "redos" and (("timeout" in _s171_msg_l) or
                                   ("exceeded" in _s171_msg_l)):
        _s171_timeout_match = True
        break
check(_s171_timeout_match,
      f"171c: errors list contains entry for 'redos' whose message "
      f"mentions 'timeout' or 'exceeded' "
      f"(got {_s171_err_entries!r})")


# =====================================================================
# Section 172 — Regex Safety: module-level _pattern_is_redos_prone helper
# =====================================================================
# Phase 3B adds a module-level heuristic function — suggested name
# _pattern_is_redos_prone(pattern) -> (bool, str) — that returns
# (True, reason) for patterns matching H1 or H2 and (False, "")
# otherwise. This is distinct from Section 170's integration test
# (which goes through _validate_capture_entry's raise path): the
# helper is the programmatic entry point callers can use without
# wrapping the question in a try/except.
#
# If Phase 3B picks a different name or return shape, update the
# getattr below and the shape assertion — the test's intent is that
# SOME such helper exists as a module-level symbol.
print("\n=== SECTION 172: Regex Safety — _pattern_is_redos_prone helper ===")

_s172_detector = getattr(scaffold, "_pattern_is_redos_prone", None)

_s172_bad_patterns = [
    r"^(a+)+$",
    r"(.*)+",
    r"(x+x+)+y",
    r"^(a|a)*$",
]

_s172_good_patterns = [
    r"(\S+)",
    r"open\s+(\d+)/tcp",
    r"^PORT:\s+(.+)$",
    r"Scan completed in (\d+\.\d+)s",
    r"([a-zA-Z0-9_-]+)",
    r"(\d{1,3}(?:\.\d{1,3}){3})",
    r"^\[.*?\]\s+(.+)",
]

for _s172_i, _s172_pat in enumerate(_s172_bad_patterns):
    if _s172_detector is None:
        check(False,
              f"172a.{_s172_i}: _pattern_is_redos_prone flags "
              f"{_s172_pat!r} as ReDoS-prone "
              f"(helper not found on scaffold module)")
        continue
    _s172_res = None
    _s172_call_exc = None
    try:
        _s172_res = _s172_detector(_s172_pat)
    except Exception as _s172_exc:
        _s172_call_exc = _s172_exc
    _s172_flag = False
    if isinstance(_s172_res, tuple) and len(_s172_res) == 2:
        _s172_flag = bool(_s172_res[0])
    check(_s172_flag,
          f"172a.{_s172_i}: _pattern_is_redos_prone({_s172_pat!r}) "
          f"returns (True, <reason>) "
          f"(got res={_s172_res!r}, exc={_s172_call_exc!r})")

for _s172_i, _s172_pat in enumerate(_s172_good_patterns):
    if _s172_detector is None:
        check(False,
              f"172b.{_s172_i}: _pattern_is_redos_prone clears "
              f"{_s172_pat!r} (helper not found on scaffold module)")
        continue
    _s172_res = None
    _s172_call_exc = None
    try:
        _s172_res = _s172_detector(_s172_pat)
    except Exception as _s172_exc:
        _s172_call_exc = _s172_exc
    _s172_ok = False
    if isinstance(_s172_res, tuple) and len(_s172_res) == 2:
        _s172_ok = not bool(_s172_res[0])
    check(_s172_ok,
          f"172b.{_s172_i}: _pattern_is_redos_prone({_s172_pat!r}) "
          f"returns (False, \"\") "
          f"(got res={_s172_res!r}, exc={_s172_call_exc!r})")


# =====================================================================
# Section 173 — _quote_token POSIX correctness
# =====================================================================
# _quote_token now uses POSIX close-escape-reopen ('\'') for tokens that
# contain both whitespace and a single quote. Previously it fell through
# to a Windows-CMD double-quote branch (doubled " chars), which was wrong
# for any POSIX shell and would not round-trip through shlex.
print("\n=== SECTION 173: _quote_token POSIX correctness ===")

import shlex as _s173_shlex

# 173a: plain token, no whitespace, no quotes → returned as-is
_s173a = scaffold._quote_token("hello")
check(_s173a == "hello",
      f"173a: plain token unchanged: {_s173a!r}")

# 173b: whitespace, no quotes → wrap in single quotes
_s173b = scaffold._quote_token("hello world")
check(_s173b == "'hello world'",
      f"173b: whitespace wraps in single quotes: {_s173b!r}")

# 173c: single quote but no whitespace → returned as-is (not quoted)
_s173c = scaffold._quote_token("it's")
check(_s173c == "it's",
      f"173c: apostrophe without whitespace unchanged: {_s173c!r}")

# 173d: whitespace AND single quote → POSIX close-escape-reopen
_s173d = scaffold._quote_token("it's a test")
check(_s173d == "'it'\\''s a test'",
      f"173d: POSIX escape for apostrophe + whitespace: {_s173d!r}")

# 173e: multiple single quotes with whitespace → each apostrophe escaped
_s173e = scaffold._quote_token("a 'b' c")
check(_s173e == "'a '\\''b'\\'' c'",
      f"173e: multiple apostrophes each escaped: {_s173e!r}")

# 173f: tab character → wrapped in single quotes
_s173f = scaffold._quote_token("a\tb")
check(_s173f == "'a\tb'",
      f"173f: tab wraps in single quotes: {_s173f!r}")

# 173g: newline character → wrapped in single quotes
_s173g = scaffold._quote_token("a\nb")
check(_s173g == "'a\nb'",
      f"173g: newline wraps in single quotes: {_s173g!r}")

# 173h: empty string → returned as-is (no whitespace)
_s173h = scaffold._quote_token("")
check(_s173h == "",
      f"173h: empty string unchanged: {_s173h!r}")

# --- Round-trip verification: shlex.split must recover the original ---

# 173i: apostrophe + whitespace round-trips through shlex
_s173i_orig = "it's a test"
_s173i_quoted = scaffold._quote_token(_s173i_orig)
_s173i_parsed = _s173_shlex.split(f"echo {_s173i_quoted}")
check(_s173i_parsed == ["echo", _s173i_orig],
      f"173i: round-trip through shlex preserves {_s173i_orig!r}: "
      f"parsed={_s173i_parsed!r}")

# 173j: multiple apostrophes + whitespace round-trips
_s173j_orig = "a 'b' c"
_s173j_quoted = scaffold._quote_token(_s173j_orig)
_s173j_parsed = _s173_shlex.split(f"echo {_s173j_quoted}")
check(_s173j_parsed == ["echo", _s173j_orig],
      f"173j: round-trip through shlex preserves {_s173j_orig!r}: "
      f"parsed={_s173j_parsed!r}")

# 173k: apostrophe + double quote + whitespace round-trips
_s173k_orig = "it's \"complex\" stuff"
_s173k_quoted = scaffold._quote_token(_s173k_orig)
_s173k_parsed = _s173_shlex.split(f"echo {_s173k_quoted}")
check(_s173k_parsed == ["echo", _s173k_orig],
      f"173k: round-trip through shlex preserves {_s173k_orig!r}: "
      f"parsed={_s173k_parsed!r}")

# 173l: consecutive apostrophes with whitespace round-trips
_s173l_orig = "can''t stop"
_s173l_quoted = scaffold._quote_token(_s173l_orig)
_s173l_parsed = _s173_shlex.split(f"echo {_s173l_quoted}")
check(_s173l_parsed == ["echo", _s173l_orig],
      f"173l: round-trip through shlex preserves {_s173l_orig!r}: "
      f"parsed={_s173l_parsed!r}")


# =====================================================================
# Section 174 — Cascade chain-button compact-QSS regression guard
# =====================================================================
# Guards the two failure modes shipped as v2.9.2:
#   (a) init loop at CascadeSidebar.__init__ only applied the compact
#       "padding: 2px 8px" QSS to 3 of 7 chain buttons — loop_btn,
#       stop_on_error_btn, clear_all_btn, and add_step_btn kept native
#       button chrome and clipped text on Linux light mode.
#   (b) _style_loop_btn and _style_stop_on_error_btn OFF branches called
#       setStyleSheet("") which wiped the padding on every _load_cascade
#       and every toggle-off.
# Regression tests for commit 6adb4de.
print("\n=== SECTION 174: Cascade chain-button compact-QSS regression guard ===")

# Clear any cascade state from prior runs so _load_cascade doesn't
# resurrect a loop_enabled=True from a previous test session.
QSettings("Scaffold", "Scaffold").remove("cascade")

_s174_win = scaffold.MainWindow()
app.processEvents()
_s174_dock = _s174_win.cascade_dock

# 174a: coverage guard — every chain button carries the compact padding.
# Mirrors the init loop at scaffold.py:5800-5803 (setStyleSheet called
# directly on each button, not an ancestor). Iterated by attribute name
# so a failure message tells you which button regressed.
_s174_chain_btns = (
    "run_chain_btn", "pause_chain_btn", "stop_chain_btn",
    "loop_btn", "stop_on_error_btn", "clear_all_btn", "add_step_btn",
)
for _s174_attr in _s174_chain_btns:
    _s174_btn = getattr(_s174_dock, _s174_attr)
    _s174_qss = _s174_btn.styleSheet()
    check("padding: 2px 8px" in _s174_qss,
          f"174a: {_s174_attr} carries compact padding at init "
          f"(stylesheet={_s174_qss!r})")

# 174b: single-source-of-truth invariant — the padding literal lives in
# _chain_btn_body only, and _chain_qss is composed from it.
check(hasattr(_s174_dock, "_chain_btn_body"),
      "174b: _chain_btn_body attribute exists")
check("padding: 2px 8px" in _s174_dock._chain_btn_body,
      f"174b: _chain_btn_body carries the padding literal "
      f"(got {_s174_dock._chain_btn_body!r})")
check(_s174_dock._chain_btn_body in _s174_dock._chain_qss,
      "174b: _chain_qss composes from _chain_btn_body (not a second literal)")

# 174c: loop_btn ON retains padding (ON branch uses _chain_btn_body).
_s174_dock._loop_enabled = False
_s174_dock._toggle_loop()  # OFF -> ON
check(_s174_dock._loop_enabled is True, "174c: loop toggled ON")
check(_s174_dock.loop_btn.text() == "Loop \u2713",
      f"174c: loop_btn text is 'Loop ✓' when ON "
      f"(got {_s174_dock.loop_btn.text()!r})")
check("padding: 2px 8px" in _s174_dock.loop_btn.styleSheet(),
      f"174c: loop_btn ON retains compact padding "
      f"(stylesheet={_s174_dock.loop_btn.styleSheet()!r})")

# 174d: loop_btn OFF retains padding — the real shipped bug. Pre-v2.9.2,
# the OFF branch called setStyleSheet("") which wiped the padding and
# let native chrome clip "Loop" on Linux.
_s174_dock._toggle_loop()  # ON -> OFF
check(_s174_dock._loop_enabled is False, "174d: loop toggled OFF")
check(_s174_dock.loop_btn.text() == "Loop \u2717",
      f"174d: loop_btn text is 'Loop \u2717' when OFF (v2.11.1+) "
      f"(got {_s174_dock.loop_btn.text()!r})")
check("padding: 2px 8px" in _s174_dock.loop_btn.styleSheet(),
      f"174d: loop_btn OFF retains compact padding "
      f"(stylesheet={_s174_dock.loop_btn.styleSheet()!r})")

# 174e: stop_on_error_btn ON retains padding.
_s174_dock._stop_on_error = False
_s174_dock._toggle_stop_on_error()  # OFF -> ON
check(_s174_dock._stop_on_error is True, "174e: stop_on_error toggled ON")
check(_s174_dock.stop_on_error_btn.text() == "Err\u2713",
      f"174e: stop_on_error_btn text is 'Err✓' when ON "
      f"(got {_s174_dock.stop_on_error_btn.text()!r})")
check("padding: 2px 8px" in _s174_dock.stop_on_error_btn.styleSheet(),
      f"174e: stop_on_error_btn ON retains compact padding "
      f"(stylesheet={_s174_dock.stop_on_error_btn.styleSheet()!r})")

# 174f: stop_on_error_btn OFF retains padding — same class of bug as 174d.
_s174_dock._toggle_stop_on_error()  # ON -> OFF
check(_s174_dock._stop_on_error is False, "174f: stop_on_error toggled OFF")
check(_s174_dock.stop_on_error_btn.text() == "Err\u2717",
      f"174f: stop_on_error_btn text is 'Err✗' when OFF "
      f"(got {_s174_dock.stop_on_error_btn.text()!r})")
check("padding: 2px 8px" in _s174_dock.stop_on_error_btn.styleSheet(),
      f"174f: stop_on_error_btn OFF retains compact padding "
      f"(stylesheet={_s174_dock.stop_on_error_btn.styleSheet()!r})")

# 174g: theme change preserves padding on every chain button. Exercises
# update_theme's hoisted self._chain_qss refresh (scaffold.py:7363) and
# the expanded refresh loop. A regression that drops clear_all_btn or
# add_step_btn from the refresh loop, or reverts the OFF-branch fix,
# would show up as missing padding after the flip.
_s174_dark_before = scaffold._dark_mode
scaffold.apply_theme(not _s174_dark_before)
app.processEvents()
for _s174_attr in _s174_chain_btns:
    _s174_btn = getattr(_s174_dock, _s174_attr)
    _s174_qss = _s174_btn.styleSheet()
    check("padding: 2px 8px" in _s174_qss,
          f"174g: {_s174_attr} keeps compact padding after theme flip "
          f"(stylesheet={_s174_qss!r})")
scaffold.apply_theme(_s174_dark_before)
app.processEvents()

# 174h: toggle + theme round-trip integration. Loop ON, flip theme, flip
# back, toggle OFF — padding must survive every step. Covers the
# wipe regression and an update_theme reordering regression in one pass.
_s174_dock._loop_enabled = False
_s174_dock._toggle_loop()  # OFF -> ON
scaffold.apply_theme(not _s174_dark_before)
app.processEvents()
check("padding: 2px 8px" in _s174_dock.loop_btn.styleSheet(),
      "174h: loop_btn ON + theme flip retains padding")
scaffold.apply_theme(_s174_dark_before)
app.processEvents()
check("padding: 2px 8px" in _s174_dock.loop_btn.styleSheet(),
      "174h: loop_btn ON + theme round-trip retains padding")
_s174_dock._toggle_loop()  # ON -> OFF
check("padding: 2px 8px" in _s174_dock.loop_btn.styleSheet(),
      "174h: loop_btn OFF after theme round-trip retains padding")

# Cleanup
_s174_win.close()
_s174_win.deleteLater()
app.processEvents()


