check(len(_s179_t17b_argvs) >= 2,
      f"T17b: both steps reached _on_run_stop (got {len(_s179_t17b_argvs)})")
if len(_s179_t17b_argvs) >= 2:
    check("/tmp/scan.log" in _s179_t17b_argvs[1],
          f"T17b: step-2 argv contains '/tmp/scan.log' "
          f"(got {_s179_t17b_argvs[1]!r})")
else:
    check(False, "T17b: step-2 argv substitution check skipped — fewer than 2 argvs")

# T17c — --output={logfile}
_s179_t17c_argvs, _s179_t17c_finish, _s179_t17c_status, _s179_t17c_state = _s179_run_cascade_capture_argv(
    step1_captures=[{"name": "logfile", "source": "stdout", "pattern": r"(READY)", "group": 1}],
    fake_extract_result={"logfile": "out.txt"},
    step2_extra_flags="--output={logfile}",
    stop_on_error=False,
)
check(len(_s179_t17c_argvs) >= 2,
      f"T17c: both steps reached _on_run_stop (got {len(_s179_t17c_argvs)})")
if len(_s179_t17c_argvs) >= 2:
    check("--output=out.txt" in _s179_t17c_argvs[1],
          f"T17c: step-2 argv contains '--output=out.txt' "
          f"(got {_s179_t17c_argvs[1]!r})")
else:
    check(False, "T17c: step-2 argv substitution check skipped — fewer than 2 argvs")

# T17d — {host}:{port} (two captures combined inside one token)
_s179_t17d_argvs, _s179_t17d_finish, _s179_t17d_status, _s179_t17d_state = _s179_run_cascade_capture_argv(
    step1_captures=[
        {"name": "host", "source": "stdout", "pattern": r"(READY)", "group": 1},
        {"name": "port", "source": "stdout", "pattern": r"(READY)", "group": 1},
    ],
    fake_extract_result={"host": "example.com", "port": "8080"},
    step2_extra_flags="{host}:{port}",
    stop_on_error=False,
)
check(len(_s179_t17d_argvs) >= 2,
      f"T17d: both steps reached _on_run_stop (got {len(_s179_t17d_argvs)})")
if len(_s179_t17d_argvs) >= 2:
    check("example.com:8080" in _s179_t17d_argvs[1],
          f"T17d: step-2 argv contains 'example.com:8080' "
          f"(got {_s179_t17d_argvs[1]!r})")
else:
    check(False, "T17d: step-2 argv substitution check skipped — fewer than 2 argvs")


# Cleanup section 179
shutil.rmtree(_s179_tmpdir, ignore_errors=True)
QSettings("Scaffold", "Scaffold").remove("cascade")
QSettings("Scaffold", "Scaffold").remove("custom_paths")
# T8 may install a stale oversized cascade pre-fix; remove if present.
# Also remove legacy "t8_oversized.json" from earlier T8 iterations.
for _s179_t8_name in ("t8_rejectme.json", "t8_oversized.json"):
    try:
        _s179_t8_stale = scaffold._cascades_dir() / _s179_t8_name
        _s179_t8_stale.unlink(missing_ok=True)
    except OSError:
        pass


# =====================================================================
print("\n=== SECTION 180: multi-subcommand same-tool cascade snapshot overlay ===")
# =====================================================================
# The v2.9.4 snapshot-overlay fix changed the merge from wholesale
# replace to per-key. Per the CHANGELOG, a documented consequence was:
# "subcommand and elevation now follow the step N preset" — the overlay
# loop iterates form.fields and handles _extra_flags, but does NOT touch
# _subcommand or _elevated, so step N's preset values for those survive.
# §179 T16 covers the per-field merge with a single-subcommand schema;
# §180 covers the subcommand/elevation complement with two subcommands.
#
# Setup: same tool both steps (so the snapshot path triggers), schema
# has two subcommands ("alpha" and "beta") each with one distinctive
# string flag. Step 1 selects alpha + sets --alpha-flag=A_VALUE +
# elevation off. Step 2 selects beta + sets --beta-flag=B_VALUE +
# elevation on. Step 2's argv must reflect preset 2's subcommand and
# flag — pre-fix wholesale-overlay would have left subcommand="alpha"
# and elevation=False, producing argv [..., "alpha", "--alpha-flag",
# "A_VALUE"] instead of [..., "beta", "--beta-flag", "B_VALUE"].

QSettings("Scaffold", "Scaffold").remove("cascade")
QSettings("Scaffold", "Scaffold").remove("session/last_tool")
_s180_tmpdir = Path(tempfile.mkdtemp(prefix="s180_"))

_s180_tool_data = {
    "_format": "scaffold_schema",
    "tool": "s180_py",
    "binary": sys.executable,
    "description": "section 180 multi-subcommand runner",
    "elevated": "optional",
    "subcommands": [
        {
            "name": "alpha",
            "description": "alpha subcommand",
            "arguments": [_s179_make_arg("Alpha", "--alpha-flag", "string")],
        },
        {
            "name": "beta",
            "description": "beta subcommand",
            "arguments": [_s179_make_arg("Beta", "--beta-flag", "string")],
        },
    ],
    "arguments": [],
}
_s180_tool_hash = scaffold.schema_hash(_s180_tool_data)
_s180_tool_path = _s180_tmpdir / "s180_tool.json"
_s180_tool_path.write_text(json.dumps(_s180_tool_data), encoding="utf-8")


def _s180_write_preset(filename, subcmd, alpha_value=None, beta_value=None,
                       elevated=False):
    """Write a §180 preset. _elevated is included unconditionally so the
    overlay's no-touch-on-elevation behavior is exercised on both steps."""
    data = {
        "_format": "scaffold_preset",
        "_tool": "s180_py",
        "_subcommand": subcmd,
        "_schema_hash": _s180_tool_hash,
        "_elevated": elevated,
    }
    if alpha_value is not None:
        data["alpha:--alpha-flag"] = alpha_value
    if beta_value is not None:
        data["beta:--beta-flag"] = beta_value
    p = _s180_tmpdir / filename
    p.write_text(json.dumps(data), encoding="utf-8")
    return p


_s180_p1 = _s180_write_preset("s180_p1.json", "alpha",
                              alpha_value="A_VALUE", elevated=False)
_s180_p2 = _s180_write_preset("s180_p2.json", "beta",
                              beta_value="B_VALUE", elevated=True)

_s180_win = scaffold.MainWindow()
_s180_win.show()
app.processEvents()
_s180_dock = _s180_win.cascade_dock
_s180_dock._cascade_variables = []
_s180_dock._stop_on_error = False

_s180_dock._slots[0]["tool_path"] = str(_s180_tool_path)
_s180_dock._slots[0]["preset_path"] = str(_s180_p1)
_s180_dock._slots[0]["captures"] = [
    {"name": "x", "source": "stdout", "pattern": r"(READY)", "group": 1}
]
_s180_dock._slots[1]["tool_path"] = str(_s180_tool_path)
_s180_dock._slots[1]["preset_path"] = str(_s180_p2)
for _s180_i in range(2, len(_s180_dock._slots)):
    _s180_dock._slots[_s180_i]["tool_path"] = None

_s180_prev_extract = scaffold.extract_captures
scaffold.extract_captures = lambda *a, **kw: ({"x": "READY"}, [])

_s180_argvs = []
# Captured at step-2 intercept; one entry means step 2 was reached.
# is_elevation_checked() returns the checkbox state when the checkbox
# exists, else short-circuits via _check_already_elevated() — both modes
# yield True after preset 2 applies, so the assertion is robust against
# elevated-shell test runs even though the meaningful signal comes from
# the checkbox-present case.
_s180_elev_capture = []
_s180_orig_stop = _s180_win._on_run_stop


def _s180_intercept():
    cmd, _ = _s180_win.form.build_command()
    _s180_argvs.append(list(cmd))
    if len(_s180_argvs) == 1:
        _s180_orig_stop()
    else:
        _s180_elev_capture.append(_s180_win.form.is_elevation_checked())
        _s180_dock._chain_cleanup("test: step 2 argv captured")


_s180_win._on_run_stop = _s180_intercept

try:
    _s180_dock._on_run_chain()
    _s179_wait_idle(_s180_dock, max_iters=300, sleep_s=0.05)
finally:
    scaffold.extract_captures = _s180_prev_extract
    _s180_win._on_run_stop = _s180_orig_stop
    _s180_win.close()
    _s180_win.deleteLater()
    app.processEvents()
    QSettings("Scaffold", "Scaffold").remove("cascade")
    QSettings("Scaffold", "Scaffold").remove("session/last_tool")

check(len(_s180_argvs) == 2,
      f"180a: both steps reached _on_run_stop (got {len(_s180_argvs)})")
if len(_s180_argvs) >= 2:
    _s180_step2 = _s180_argvs[1]
    check("beta" in _s180_step2,
          f"180b: step-2 argv contains 'beta' subcommand token "
          f"(got {_s180_step2!r})")
    check("--beta-flag" in _s180_step2,
          f"180c: step-2 argv contains '--beta-flag' from preset 2 "
          f"(got {_s180_step2!r})")
    if "--beta-flag" in _s180_step2:
        _s180_idx = _s180_step2.index("--beta-flag")
        check(_s180_idx + 1 < len(_s180_step2)
              and _s180_step2[_s180_idx + 1] == "B_VALUE",
              f"180d: step-2 argv has 'B_VALUE' immediately after "
              f"'--beta-flag' (got {_s180_step2!r})")
    else:
        check(False, "180d: B_VALUE adjacency check skipped — "
                     "--beta-flag missing")
    # Note: the overlay DOES write step-1's "alpha:--alpha-flag" into the
    # inactive alpha-scope field at step 2. Harmless because build_command
    # scopes by active subcommand ("beta") — but worth knowing if scope
    # filtering in build_command or the overlay loop is ever refactored.
    check("alpha" not in _s180_step2,
          f"180e: step-2 argv does NOT contain 'alpha' (step-1 "
          f"subcommand did not leak via overlay) (got {_s180_step2!r})")
    check("--alpha-flag" not in _s180_step2,
          f"180f: step-2 argv does NOT contain '--alpha-flag' (step-1 "
          f"flag did not leak via overlay) (got {_s180_step2!r})")
    check("A_VALUE" not in _s180_step2,
          f"180g: step-2 argv does NOT contain 'A_VALUE' (step-1 flag "
          f"value did not leak via overlay) (got {_s180_step2!r})")
    check(len(_s180_elev_capture) == 1 and _s180_elev_capture[0] is True,
          f"180h: step-2 elevation reflects preset 2's _elevated=True "
          f"(got {_s180_elev_capture!r})")
else:
    check(False, "180b: 'beta' check skipped — fewer than 2 argvs")
    check(False, "180c: --beta-flag check skipped")
    check(False, "180d: B_VALUE adjacency check skipped")
    check(False, "180e: alpha-not-in check skipped")
    check(False, "180f: --alpha-flag-not-in check skipped")
    check(False, "180g: A_VALUE-not-in check skipped")
    check(False, "180h: elevation check skipped")


# Cleanup section 180
shutil.rmtree(_s180_tmpdir, ignore_errors=True)
QSettings("Scaffold", "Scaffold").remove("cascade")
QSettings("Scaffold", "Scaffold").remove("session/last_tool")


# =====================================================================
print("\n=== SECTION 181: _read_user_json size-cap regression at remaining call sites ===")
# =====================================================================
# v2.9.4 introduced _read_user_json (2 MB cap via MAX_PRESET_SIZE) as a
# single entry point for user-supplied JSON. §179 T7 covers the cascade-
# step preset resolution path (chain runner, scaffold.py:7225) and T8
# covers cascade import (scaffold.py:6660). The other three
# _read_user_json call sites are not directly guarded by §179:
#   • CascadeDock._on_load_cascade_list (scaffold.py:6562) — load a
#     cascade picked from the Cascade List dialog.
#   • PresetPicker._on_edit_description (scaffold.py:3555) — read a
#     preset to edit its _description in the edit-mode picker.
#   • CascadeDock._on_slot_clicked (scaffold.py:6807) — left-click a
#     configured slot; tool is loaded then preset is applied.
# §181 adds focused regression tests so a future refactor that bypasses
# _read_user_json at any of those sites fails loudly. Each test plants
# an oversized JSON (> MAX_PRESET_SIZE), drives the public entry point,
# and asserts the rejection took effect (no install / no apply / no
# write) and the user was informed (status bar or QMessageBox).

QSettings("Scaffold", "Scaffold").remove("cascade")
QSettings("Scaffold", "Scaffold").remove("session/last_tool")
_s181_tmpdir = Path(tempfile.mkdtemp(prefix="s181_"))


def _s181_make_oversized_preset(path, code="ORIG"):
    """Write a >MAX_PRESET_SIZE preset JSON file matching the s181 schema."""
    data = {
        "_format": "scaffold_preset",
        "_tool": "s181_py",
        "_subcommand": None,
        "_padding": "X" * (3 * 1024 * 1024),
        "-c": code,
    }
    path.write_text(json.dumps(data), encoding="utf-8")
    return path


def _s181_make_oversized_cascade(path, name="s181_rejectme"):
    """Write a >MAX_PRESET_SIZE cascade JSON file."""
    data = {
        "_format": "scaffold_cascade",
        "name": name,
        "description": "oversized cascade — should never be loaded",
        "loop_mode": False,
        "stop_on_error": False,
        "variables": [],
        "steps": [],
        "_padding": "Y" * (3 * 1024 * 1024),
    }
    path.write_text(json.dumps(data), encoding="utf-8")
    return path


# Shared minimal tool schema for 181b/181c (181a doesn't need a tool).
_s181_tool_data = {
    "_format": "scaffold_schema",
    "tool": "s181_py",
    "binary": sys.executable,
    "description": "section 181 runner",
    "elevated": None,
    "subcommands": None,
    "arguments": [_s179_make_arg("Code", "-c", "string")],
}
_s181_tool_path = _s181_tmpdir / "s181_tool.json"
_s181_tool_path.write_text(json.dumps(_s181_tool_data), encoding="utf-8")


# ---------------------------------------------------------------
# 181a — oversized cascade JSON loaded via the Cascade List dialog:
#         rejected with size error, no slots populated.
# ---------------------------------------------------------------
print("\n--- 181a: oversized cascade in Cascade List → rejected with size error ---")

_s181a_path = _s181_make_oversized_cascade(_s181_tmpdir / "s181a_oversized.json")
check(_s181a_path.stat().st_size > scaffold.MAX_PRESET_SIZE,
      f"181a: cascade size {_s181a_path.stat().st_size} exceeds MAX_PRESET_SIZE "
      f"({scaffold.MAX_PRESET_SIZE})")

_s181a_win = scaffold.MainWindow()
_s181a_win.show()
app.processEvents()
_s181a_dock = _s181a_win.cascade_dock


# Stub CascadeListDialog: avoids opening a real dialog and lets us inject
# the oversized path. The handler reads dlg.selected_path after exec();
# the attribute and the method are all that's needed.
class _S181aFakeDialog:
    def __init__(self, *args, **kwargs):
        self.selected_path = str(_s181a_path)

    def exec(self):
        return 1  # QDialog.DialogCode.Accepted


_s181a_orig_dialog = scaffold.CascadeListDialog
scaffold.CascadeListDialog = _S181aFakeDialog

try:
    _s181a_dock._on_load_cascade_list()
    app.processEvents()

    _s181a_status = _s181a_win.statusBar().currentMessage().lower()

    # Strongest check: the oversized cascade did NOT install into any slot.
    check(not any(s.get("tool_path") for s in _s181a_dock._slots),
          f"181a: oversized cascade NOT applied to slots "
          f"(slots[0]={_s181a_dock._slots[0]!r})")
    # Status must surface the size rejection.
    check(any(tok in _s181a_status for tok in ("too large", "exceeds", "limit", "bytes")),
          f"181a: status surfaces size error (got {_s181a_status!r})")
    # Status must specifically name a cascade-load failure (not some
    # other generic error from elsewhere in the dock).
    check("error loading cascade" in _s181a_status,
          f"181a: status names 'error loading cascade' (got {_s181a_status!r})")
finally:
    scaffold.CascadeListDialog = _s181a_orig_dialog
    _s181a_win.close()
    _s181a_win.deleteLater()
    app.processEvents()
    QSettings("Scaffold", "Scaffold").remove("cascade")


# ---------------------------------------------------------------
# 181b — PresetPicker._on_edit_description with oversized preset:
#         QMessageBox.warning surfaces, file unchanged on disk.
# ---------------------------------------------------------------
print("\n--- 181b: oversized preset in edit-description → warning, file unchanged ---")

_s181b_presets_dir = _s181_tmpdir / "s181b_presets"
_s181b_presets_dir.mkdir()
_s181b_preset = _s181_make_oversized_preset(
    _s181b_presets_dir / "s181b_huge.json", code="ORIG"
)
check(_s181b_preset.stat().st_size > scaffold.MAX_PRESET_SIZE,
      f"181b: preset size {_s181b_preset.stat().st_size} exceeds MAX_PRESET_SIZE")

# Snapshot bytes so we can prove _atomic_write_json never ran.
_s181b_before_bytes = _s181b_preset.read_bytes()

_s181b_picker = scaffold.PresetPicker(
    tool_name="s181_tool",
    presets_dir=_s181b_presets_dir,
    mode="edit",
)
app.processEvents()

try:
    _s181b_picker.table.selectRow(0)
    app.processEvents()

    with _patch_qmb("warning") as _s181b_warnings:
        _s181b_picker._on_edit_description()
        app.processEvents()

    _s181b_text = " ".join(t + " " + m for t, m in _s181b_warnings).lower()

    # File must be byte-for-byte unchanged (no _description was written).
    check(_s181b_preset.read_bytes() == _s181b_before_bytes,
          "181b: oversized preset file unchanged on disk after rejection")
    # Warning text must mention size — guards against a regression that
    # silently re-routes through _read_json_file (which has no size cap)
    # and then fails for some other downstream reason.
    check(any(tok in _s181b_text for tok in ("too large", "exceeds", "limit", "bytes")),
          f"181b: warning surfaces size error (got {_s181b_warnings!r})")
finally:
    _s181b_picker.close()
    _s181b_picker.deleteLater()
    app.processEvents()
    # PresetPicker writes to favorites/<tool_name> in QSettings during
    # __init__ → _save_favorites if any pruning happens. Always remove
    # the key to keep user QSettings clean.
    QSettings("Scaffold", "Scaffold").remove("favorites/s181_tool")


# ---------------------------------------------------------------
# 181c — CascadeDock._on_slot_clicked with oversized preset: tool loads
#         (happens before the preset read), preset is NOT applied to the
#         form, status names the rejection.
# ---------------------------------------------------------------
print("\n--- 181c: oversized preset on slot click → preset rejected, form not modified ---")

_s181c_preset = _s181_make_oversized_preset(
    _s181_tmpdir / "s181c_oversized.json", code="SHOULD_NOT_APPLY"
)
check(_s181c_preset.stat().st_size > scaffold.MAX_PRESET_SIZE,
      f"181c: preset size {_s181c_preset.stat().st_size} exceeds MAX_PRESET_SIZE")

_s181c_win = scaffold.MainWindow()
_s181c_win.show()
app.processEvents()
_s181c_dock = _s181c_win.cascade_dock

try:
    _s181c_dock._slots[0]["tool_path"] = str(_s181_tool_path)
    _s181c_dock._slots[0]["preset_path"] = str(_s181c_preset)

    _s181c_dock._on_slot_clicked(0)
    app.processEvents()

    _s181c_status = _s181c_win.statusBar().currentMessage().lower()

    # Tool must have loaded — _load_tool_path runs BEFORE the preset read,
    # so an oversized preset must not prevent the tool from loading.
    check(_s181c_win.tool_path is not None
          and Path(_s181c_win.tool_path).resolve() == _s181_tool_path.resolve(),
          f"181c: tool loaded before preset rejection "
          f"(got tool_path={_s181c_win.tool_path!r})")
    # The preset's "-c" sentinel must NOT have reached the form — proves
    # apply_values was never called on the rejected preset.
    _s181c_c_value = _s181c_win.form.get_field_value(
        ("__global__", "-c")
    ) if _s181c_win.form is not None else None
    check("SHOULD_NOT_APPLY" not in str(_s181c_c_value),
          f"181c: -c field NOT populated by oversized preset "
          f"(got {_s181c_c_value!r})")
    # Status must name the rejection — distinguishes this branch from
    # the success branch ("Loaded cascade step: …").
    check("preset not loaded" in _s181c_status,
          f"181c: status names 'preset not loaded' (got {_s181c_status!r})")
finally:
    _s181c_win.close()
    _s181c_win.deleteLater()
    app.processEvents()
    QSettings("Scaffold", "Scaffold").remove("cascade")
    QSettings("Scaffold", "Scaffold").remove("session/last_tool")


# Cleanup section 181
shutil.rmtree(_s181_tmpdir, ignore_errors=True)
QSettings("Scaffold", "Scaffold").remove("cascade")
QSettings("Scaffold", "Scaffold").remove("session/last_tool")
QSettings("Scaffold", "Scaffold").remove("favorites/s181_tool")
# Defensive: 181a stubs the dialog and writes the oversized cascade
# only to tmpdir, so nothing should land in the real cascades dir. If a
# future refactor changes that, this catches the leak.
for _s181_stale_name in ("s181a_oversized.json", "s181_rejectme.json"):
    try:
        (scaffold._cascades_dir() / _s181_stale_name).unlink(missing_ok=True)
    except OSError:
        pass


print("\n=== SECTION 182: cascade-side malformed preset rejection ===")
# =====================================================================
# v2.9.3 shipped a _schema_hash mismatch halt at the cascade-step preset
# resolution site (_chain_advance, scaffold.py:7225) to stop stale-preset
# silent-run. The adjacent gap — preset missing _format, wrong _format,
# or with a _tool mismatch — was not guarded. apply_values tolerates
# missing meta keys, so a malformed preset silently produced a wrong
# command when consumed during a cascade run. The _on_slot_clicked
# interactive load path (scaffold.py:6807) had the same gap.
#
# §182 pins the rejection behavior at both sites:
#   - Site 4 (_on_slot_clicked): status-bar message, form NOT modified.
#   - Site 5 (_chain_advance):   _cascade_finish_status == "error_halted",
#     _chain_cleanup halt message names the specific marker problem.
# Both sites stderr-log a forensic [cascade] line with the file path and
# current-tool context for post-mortem debugging.
#
# Positive coverage for Site 5 (valid-marker preset progresses through a
# cascade run) is provided by §179 T17 (T17a-T17d exercise
# _s179_run_cascade_capture_argv which writes markered presets via
# _s179_write_preset). §182 T1 adds Site 4's positive regression guard.
#
# Negative coverage picks the most representative variants per site based
# on Step 1 findings: missing _format (V1 — the most common silent-fall-
# through from hand-edited or externally-generated presets), _tool
# mismatch (V2-shaped — user moved a preset between tools), and wrong
# _format == "scaffold_cascade" (V5-shaped — user pointed at a cascade
# file). Truncated-JSON (V6) errors cleanly through the existing
# JSONDecodeError branch and does not need new coverage.

QSettings("Scaffold", "Scaffold").remove("cascade")
QSettings("Scaffold", "Scaffold").remove("session/last_tool")
_s182_tmpdir = Path(tempfile.mkdtemp(prefix="s182_"))

_s182_tool_data = {
    "_format": "scaffold_schema",
    "tool": "s182_py",
    "binary": sys.executable,
    "description": "section 182 runner",
    "elevated": None,
    "subcommands": None,
    "arguments": [_s179_make_arg("Code", "-c", "string")],
}
_s182_tool_hash = scaffold.schema_hash(_s182_tool_data)
_s182_tool_path = _s182_tmpdir / "s182_tool.json"
_s182_tool_path.write_text(json.dumps(_s182_tool_data), encoding="utf-8")


def _s182_write_preset(name, markers=None, code="import sys; sys.stdout.write('OK\\n')"):
    """Write a preset file; *markers* overrides defaults.

    Defaults produce a valid preset. Pass markers={"_format": None} to
    omit _format; {"_tool": "other"} to set a mismatching _tool; etc.
    Keys with value None are removed from the preset.
    """
    data = {
        "_format": "scaffold_preset",
        "_tool": "s182_py",
        "_subcommand": None,
        "_schema_hash": _s182_tool_hash,
        "-c": code,
    }
    if markers:
        for k, v in markers.items():
            if v is None and k in data:
                del data[k]
            else:
                data[k] = v
    p = _s182_tmpdir / name
    p.write_text(json.dumps(data), encoding="utf-8")
    return p


